import ApiService, { ResponseType } from "@/api/api";

const getAppDetails = (obj: {
  pkg_name: string;
  token: string;
  deviceSn: string;
  bus_bu: number;
}): ResponseType<string> => {
  return ApiService.post(
    "/parent/appstore/api/v1/app/detail",
    obj,
    {
      headers: {
        'X-Tal-BusBu': obj.bus_bu
      }
    }
  );
};

const handleApp = (obj: {
  token: string;
  pkg_name: string;
  cmd_type: string;
  deviceSn: string;
  bus_bu: number;
}): ResponseType<string> => {
  const header = {}
  return ApiService.post(
    "/parent/appstore/api/v1/control/push",
    obj,
    {
      headers: {
        'X-Tal-BusBu': obj.bus_bu
      }
    }
  );
};
export default {
  getAppDetails,
  handleApp
};
